using UnityEngine;

public class GameController : MonoBehaviour
{
    // Public player stats
    public int currentHealth = 100;
    public int maxHealth = 100;
    public int currency = 50;
    public float baseDamage = 10f;

    // Shop item settings
    public int healthUpgradePrice = 20;
    public int damageUpgradePrice = 30;
    public int healthUpgradeAmount = 10;
    public float damageUpgradeAmount = 2f;

    void Start()
    {
        Debug.Log("Game started. Health: " + currentHealth + ", Currency: " + currency);
    }

    // Applies damage calculated on the client side
    public void TakeDamage(int incomingDamage)
    {
        int netDamage = CalculateDamage(incomingDamage);
        currentHealth -= netDamage;
        if (currentHealth < 0)
        {
            currentHealth = 0;
        }
        Debug.Log("Took " + netDamage + " damage. Current health: " + currentHealth);
    }

    // Client-side damage calculation
    public int CalculateDamage(int baseDamageAmount)
    {
        // Additional calculations or modifiers can be added here.
        return baseDamageAmount;
    }

    // Purchase a health upgrade from the shop
    public void PurchaseHealthUpgrade()
    {
        if (currency >= healthUpgradePrice)
        {
            currency -= healthUpgradePrice;
            maxHealth += healthUpgradeAmount;
            currentHealth += healthUpgradeAmount; // Optionally heal the player when upgrading
            Debug.Log("Purchased Health Upgrade. New max health: " + maxHealth + ". Remaining currency: " + currency);
        }
        else
        {
            Debug.Log("Not enough currency for Health Upgrade.");
        }
    }

    // Purchase a damage upgrade from the shop
    public void PurchaseDamageUpgrade()
    {
        if (currency >= damageUpgradePrice)
        {
            currency -= damageUpgradePrice;
            baseDamage += damageUpgradeAmount;
            Debug.Log("Purchased Damage Upgrade. New base damage: " + baseDamage + ". Remaining currency: " + currency);
        }
        else
        {
            Debug.Log("Not enough currency for Damage Upgrade.");
        }
    }

    // Method to simulate earning currency (e.g., after completing a level or enemy defeat)
    public void EarnCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Earned " + amount + " currency. Total currency: " + currency);
    }
    
    // Example methods to demonstrate damage and shop purchases.
    // In a real game these would be triggered by gameplay events or UI interactions.
    void Update()
    {
        // Simulate taking damage with the D key.
        if (Input.GetKeyDown(KeyCode.D))
        {
            TakeDamage(15);
        }

        // Simulate earning currency with the E key.
        if (Input.GetKeyDown(KeyCode.E))
        {
            EarnCurrency(10);
        }

        // Simulate purchasing a health upgrade with the H key.
        if (Input.GetKeyDown(KeyCode.H))
        {
            PurchaseHealthUpgrade();
        }

        // Simulate purchasing a damage upgrade with the J key.
        if (Input.GetKeyDown(KeyCode.J))
        {
            PurchaseDamageUpgrade();
        }
    }
